import{_ as s,o as t,c as i,a2 as o}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"33 · Windows 使用要点：原生还是 WSL，到底怎么跑才省心","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"codex/33-windows.md","filePath":"codex/33-windows.md"}'),d={name:"codex/33-windows.md"};function a(n,e,l,p,c,h){return t(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="_33-·-windows-使用要点-原生还是-wsl-到底怎么跑才省心" tabindex="-1">33 · Windows 使用要点：原生还是 WSL，到底怎么跑才省心 <a class="header-anchor" href="#_33-·-windows-使用要点-原生还是-wsl-到底怎么跑才省心" aria-label="Permalink to &quot;33 · Windows 使用要点：原生还是 WSL，到底怎么跑才省心&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇〔<a href="./32-migrate-from-claude-code">32 从 Claude Code 迁移</a> 〕讲的是「用熟了 Claude Code，怎么平滑切到 Codex」。这一篇专门给 Windows 用户开小灶——前面三十多篇默认你在 Mac 或 Linux 上敲命令，可咱们国内一大半人手里是 Windows，路径、换行、沙箱全是另一套规矩。下一篇〔<a href="./34-capstone">34 综合实战</a> 〕把整个 Codex 篇学到的东西串成一个完整项目跑一遍。</p></blockquote><p>说个我自己干过的蠢事。</p><p>2026 年 3 月我第一次在公司那台 Windows 11 笔记本上装 Codex，图省事没装 WSL，直接原生 PowerShell 里就跑了。装是装上了，结果一让它改文件就报错——我盯着日志看了半天，才发现是我从 Mac 那边 <code>git clone</code> 下来的项目，里面一堆脚本是 <code>LF</code> 换行，Git 在 Windows 上默认把它们全转成了 <code>CRLF</code>，Codex 改完一保存，整个文件的 diff 全是 <code>^M</code>，等于每一行都被「改」过一遍。我还以为是 Codex 出 bug 了，提了半天 issue 草稿，最后发现是自己根本没搞懂 Windows 那套换行规矩。</p><p><strong>说句实话，Codex 在 Windows 上现在真能原生跑，体验也不差，但它跟 Mac/Linux 不是一回事。</strong> 沙箱机制是 Windows 专属的两套，路径是反斜杠，换行符是历史包袱，这些坑你不提前知道，迟早会踩。</p><p><strong>先划清范围：本篇讲的是 Windows 下的 Codex CLI，也就是终端里的用法。</strong> 如果你只用 Codex 桌面 App 或 IDE 扩展，装好就能用，基本没这些事——下面的 PowerShell、WSL、沙箱模式、路径换行排查，全是 CLI 场景的门道。</p><p>这一篇就把 Windows 上的门道讲清楚：<strong>怎么装、原生还是 WSL 怎么选、Windows 特有的三个坑怎么躲、沙箱跟 Mac/Linux 差在哪，最后亲手在 PowerShell 里跑通一个最小例子。</strong></p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>一句话结论：Windows 上最省心的跑法到底是哪种，先别纠结</li><li>用官方 PowerShell 脚本把 Codex 装上的完整步骤，外加几个 Windows 必备前置依赖</li><li>「原生 PowerShell vs WSL2」的取舍清单：你是哪种人、该选哪条路</li><li>Windows 特有的三个坑——路径反斜杠、<code>CRLF</code> 换行、<code>Everyone</code> 权限警告——怎么提前躲掉</li><li>Windows 沙箱的 <code>elevated</code> / <code>unelevated</code> 两种模式跟 Mac/Linux 的差异，以及报错 <code>1385</code> / <code>1223</code> 怎么办</li><li>一套能照做的动手流程，在 Windows 上从零跑通第一个 Codex 任务</li></ul><blockquote><p>⚠️ 命令、配置项、默认行为一律以 Codex <a href="https://developers.openai.com/codex/windows" target="_blank" rel="noreferrer">官方文档</a> 为准；模型名、套餐范围、版本号会随更新变动，以你本地 <code>codex --help</code> 和实际界面为准。本篇所有命令我都标了在 PowerShell 还是 WSL shell 里跑，别跑错地方。</p></blockquote><hr><h2 id="_01-一句话结论-windows-上最省心的跑法" tabindex="-1">01 一句话结论：Windows 上最省心的跑法 <a class="header-anchor" href="#_01-一句话结论-windows-上最省心的跑法" aria-label="Permalink to &quot;01 一句话结论：Windows 上最省心的跑法&quot;">​</a></h2><p>先把结论甩出来，省得你纠结半天：</p><p><strong>默认就用「原生 Windows + <code>elevated</code> 沙箱」，这是官方推荐的跑法，速度最快、安全性不打折。</strong> 只有当你的工作流本来就泡在 Linux 里、或者两种原生沙箱模式在你公司电脑上都跑不起来时，才退回去用 WSL2。</p><p>我知道网上很多老教程（包括一些中文站）会告诉你「Windows 上推荐 <code>unelevated</code>」「推荐先装 WSL」——<strong>这些说法过时了。</strong> 官方文档现在白纸黑字写着：原生 Windows 沙箱性能最好、速度最快，同时安全性跟其他平台一样；<code>elevated</code> 是首选，<code>unelevated</code> 只是退路。</p><p><strong>类比：装宽带。</strong> 师傅上门先给你接光纤入户（<code>elevated</code>），这是最快最稳的方案；只有当你家楼里没光纤、布线被物业卡住了，才退而求其次拉根网线走 LAN（<code>unelevated</code>）；实在都不行，才考虑搬去隔壁有网的房间办公（WSL2）。多数人家里直接接光纤就完事，根本用不着折腾后两种。</p><p>实际场景里，这个选择对应三类人：</p><ul><li><strong>你就想在 Windows 上正常写代码、用 Windows 的工具链</strong>——原生跑，<code>elevated</code>，不用想。</li><li><strong>你是公司发的「管控电脑」，IT 锁死了管理员权限</strong>——原生 <code>elevated</code> 装不上，先用 <code>unelevated</code> 顶着，同时找 IT 报备。</li><li><strong>你本来项目就在 WSL 里、用惯了 Linux 工具</strong>——直接进 WSL2 跑，别在 Windows 和 Linux 之间反复横跳。</li></ul><blockquote><p>💡 一句话总结：默认「原生 Windows + <code>elevated</code>」，WSL2 是给「本来就活在 Linux 里」的人留的，不是默认起手式。</p></blockquote><hr><h2 id="_02-安装与前置依赖" tabindex="-1">02 安装与前置依赖 <a class="header-anchor" href="#_02-安装与前置依赖" aria-label="Permalink to &quot;02 安装与前置依赖&quot;">​</a></h2><p>Windows 上装 Codex CLI，官方最直接的路子是用自带的 PowerShell 安装脚本，一行就能装上。</p><p><strong>在 PowerShell 或 Windows Terminal 里跑：</strong></p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">powershell </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ExecutionPolicy ByPass </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;irm https://chatgpt.com/codex/install.ps1 | iex&quot;</span></span></code></pre></div><p>如果你电脑上已经装了 Node.js，也可以走 npm 这条官方备选路径：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">g @openai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">codex</span></span></code></pre></div><p>装完关掉终端重开一个，让 <code>PATH</code> 生效，然后验证：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">codex </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version</span></span></code></pre></div><p>预期输出是一行版本号（具体数字以你装的为准），格式大致是 <code>codex 0.x.x</code>，能打印出来就说明装好了。</p><blockquote><p>想要图形界面而不是命令行？官方提供 Windows 桌面版 Codex app，直接从 Microsoft Store 下载；不想打开 Store 界面也可以用 <code>winget install Codex -s msstore</code> 装。本篇讲的是 CLI，下面的命令都围绕 <code>codex</code> 命令行展开。</p></blockquote><p><strong>几个前置依赖，提前备齐能少踩坑：</strong></p><table tabindex="0"><thead><tr><th>依赖</th><th>为什么需要</th><th>怎么搞定</th></tr></thead><tbody><tr><td>Windows 11（推荐）</td><td>官方首选基线，最稳</td><td>升级到 Win 11；Win 10 也能跑但要 1809 或更新版本</td></tr><tr><td><code>winget</code> 可用</td><td>装 C++ 构建工具、桌面版 app 都会用到它</td><td>缺了就更新 Windows 或装 App Installer</td></tr><tr><td>管理员审批权限</td><td><code>elevated</code> 沙箱的初始化要它</td><td>自己的电脑直接点「同意」；公司电脑可能被锁</td></tr><tr><td>C++ 构建工具（用 IDE 扩展时）</td><td>部分原生依赖要编译</td><td><code>winget install --id Microsoft.VisualStudio.2022.BuildTools -e</code></td></tr></tbody></table><p>我自己第一次在 Windows 10 上装的时候，IDE 扩展装好了却一直「转圈不响应」，折腾了快二十分钟才在官方文档的排障节里翻到——是缺了 Visual Studio Build Tools 的 C++ 工作负载。补上那条 <code>winget install</code> 命令、重启 VS Code，立马就好了。<strong>所以如果你也用 VS Code 里的 Codex 扩展，建议一开始就把 C++ 构建工具备上。</strong></p><blockquote><p>💡 一句话总结：一条 PowerShell 安装脚本搞定 Codex CLI 主体，前置就盯紧 Windows 版本、<code>winget</code> 可用、管理员权限三样。</p></blockquote><hr><h2 id="_03-wsl-vs-原生-powershell-你是哪种人" tabindex="-1">03 WSL vs 原生 PowerShell：你是哪种人 <a class="header-anchor" href="#_03-wsl-vs-原生-powershell-你是哪种人" aria-label="Permalink to &quot;03 WSL vs 原生 PowerShell：你是哪种人&quot;">​</a></h2><p>这是 Windows 用户最该先想明白的一道选择题。别看网上吵得凶，标准其实很简单：<strong>看你的代码和日常工作流活在哪儿。</strong></p><p><strong>类比：在哪个城市落户。</strong> 原生 PowerShell 就是「在 Windows 这座城落户」，办事走 Windows 那套流程，最快最顺；WSL2 是「在城里租了套 Linux 的房子」，你想用 Linux 的工具、跑 Linux 的脚本，就钻进去办公。两边都能住，但你总不能每天从 Windows 这间办公室跑去 Linux 那间再跑回来——选定一个主工位更省心。</p><p>直接上对照表：</p><table tabindex="0"><thead><tr><th>维度</th><th>原生 PowerShell</th><th>WSL2</th></tr></thead><tbody><tr><td>安装难度</td><td>✅ 一条安装脚本搞定</td><td>❌ 还要先 <code>wsl --install</code> 装发行版</td></tr><tr><td>速度</td><td>✅ 原生最快</td><td>文件 I/O 稍慢，跨盘符更慢</td></tr><tr><td>沙箱实现</td><td>Windows 专属（<code>elevated</code>/<code>unelevated</code>）</td><td>走 Linux 的 <code>bubblewrap</code> 沙箱</td></tr><tr><td>适合的工具链</td><td>✅ Windows 原生工具、<code>.exe</code></td><td>✅ Linux 原生工具、bash 脚本</td></tr><tr><td>适合谁</td><td>大多数 Windows 用户</td><td>项目本来就在 Linux 里的人</td></tr></tbody></table><p><strong>什么时候选原生 PowerShell？</strong> 你就是个普通 Windows 用户，平时用 VS Code 写代码、用 Windows 的 Git——直接原生，别装 WSL 给自己加负担。</p><p><strong>什么时候选 WSL2？</strong> 三种情况：你需要 Linux 原生工具链；你的仓库和工作流本来就在 WSL2 里；或者两种原生沙箱模式在你电脑上都跑不通。</p><p>要走 WSL2，先在「管理员身份的 PowerShell」里装：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">wsl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">wsl</span></span></code></pre></div><p>进了 WSL shell 之后，<strong>Codex 要在 Linux 里重新装一遍</strong>（Windows 上装的那个不算）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://chatgpt.com/codex/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span></span></code></pre></div><p>这里有个我 2026 年 4 月踩过的坑：我图方便把仓库放在了 <code>/mnt/c/Users/...</code> 下（也就是 Windows 的 C 盘，从 WSL 里挂载访问），结果 Codex 跑起来卡得要命，一个 <code>git status</code> 都要等好几秒。后来才知道，<strong>WSL 访问 Windows 挂载盘（<code>/mnt/c/...</code>）的文件 I/O 特别慢</strong>，得把仓库挪到 Linux 原生的主目录下：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/code</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/code</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/your/repo.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> repo</span></span></code></pre></div><p>挪完之后速度立马正常。需要从 Windows 这边访问这些文件时，在资源管理器里输 <code>\\\\wsl$\\Ubuntu\\home\\&lt;user&gt;</code> 就能进去（把 <code>&lt;user&gt;</code> 替换成你的 Linux 用户名）。另外提一句，WSL1 从 Codex <code>0.115</code> 起就不支持了（沙箱换成了 <code>bubblewrap</code>），你装 WSL 的时候默认就是 WSL2，不用特意操心。</p><blockquote><p>💡 一句话总结：代码在 Windows 就用原生 PowerShell，代码在 Linux 就用 WSL2 并把仓库放进 <code>~/</code> 而不是 <code>/mnt/c</code>。</p></blockquote><hr><h2 id="_04-windows-特有的三个坑-路径、换行、权限" tabindex="-1">04 Windows 特有的三个坑：路径、换行、权限 <a class="header-anchor" href="#_04-windows-特有的三个坑-路径、换行、权限" aria-label="Permalink to &quot;04 Windows 特有的三个坑：路径、换行、权限&quot;">​</a></h2><p>这一节是本篇的核心。Mac/Linux 用户碰不到的坑，Windows 上一个不少。</p><h3 id="坑一-路径反斜杠" tabindex="-1">坑一：路径反斜杠 <a class="header-anchor" href="#坑一-路径反斜杠" aria-label="Permalink to &quot;坑一：路径反斜杠&quot;">​</a></h3><p>Windows 路径用反斜杠 <code>C:\\Users\\You\\project</code>，Unix 用正斜杠 <code>/home/you/project</code>。Codex 大多数时候会自动处理这个差异，但有两个地方你得自己上心：</p><ul><li><strong>写进 <code>~/.codex/config.toml</code> 的路径</strong>，建议老老实实写绝对路径，比如 <code>C:\\absolute\\directory\\path</code>。</li><li><strong>给 Codex 加沙箱可读目录时</strong>，路径必须是「已存在的绝对目录」。命令是这个（<strong>在 Codex 交互界面里输</strong>）：</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/sandbox-add-read-dir C:\\absolute\\directory\\path</span></span></code></pre></div><p>执行成功后，本次会话里后续在沙箱中跑的命令就能读这个目录了。注意这条只对当前会话有效，重开一个会话要重新加。</p><h3 id="坑二-crlf-换行符-开篇我栽的那个" tabindex="-1">坑二：CRLF 换行符（开篇我栽的那个） <a class="header-anchor" href="#坑二-crlf-换行符-开篇我栽的那个" aria-label="Permalink to &quot;坑二：CRLF 换行符（开篇我栽的那个）&quot;">​</a></h3><p>先说清楚：这其实是 Windows 上用 Git 的通用换行问题，不是 Codex 自己的毛病，但 Codex 会改文件，所以你特别容易在它身上撞见。</p><p><strong>类比：南北方插座。</strong> <code>LF</code>（Unix 换行）和 <code>CRLF</code>（Windows 换行）就像两国不同制式的插座，看着都是「换行」，底层多了个 <code>\\r</code>。你从 Mac/Linux 同事那 clone 来的项目是 <code>LF</code>，到了 Windows 上 Git 可能默认给你转成 <code>CRLF</code>，Codex 一改一保存，整个文件每行都「变」了，diff 直接爆炸。</p><p>我当时就是这么栽的。解决办法是统一换行策略，最省事的是在项目根目录放个 <code>.gitattributes</code> 文件，让 Git 别瞎转：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>* text=auto eol=lf</span></span></code></pre></div><p>或者全局把 Git 的自动转换关掉（<strong>在 PowerShell 里跑</strong>）：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git config </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">global core.autocrlf false</span></span></code></pre></div><p><strong>到底用哪种看团队约定</strong>，但核心就一句：别让换行符在平台间被偷偷改掉，否则你和 Codex 的每次改动都会被换行噪音淹没。</p><h3 id="坑三-everyone-可写权限警告" tabindex="-1">坑三：<code>Everyone</code> 可写权限警告 <a class="header-anchor" href="#坑三-everyone-可写权限警告" aria-label="Permalink to &quot;坑三：\`Everyone\` 可写权限警告&quot;">​</a></h3><p>原生跑的时候，Codex 可能会警告「某些文件夹对 <code>Everyone</code> 可写」。这不是 bug——它在提醒你：<strong>这些文件夹的 Windows 权限太宽了，沙箱保护不住它们。</strong> 处理办法是去掉那些文件夹的 <code>Everyone</code> 写权限，然后重启 Codex 或重跑一次沙箱初始化。不确定怎么改权限就找 IT，别硬来。</p><table tabindex="0"><thead><tr><th>坑</th><th>症状</th><th>怎么躲</th></tr></thead><tbody><tr><td>路径反斜杠</td><td>配置/读目录路径不生效</td><td>写绝对路径，<code>/sandbox-add-read-dir</code> 用已存在的绝对目录</td></tr><tr><td><code>CRLF</code> 换行</td><td>diff 里每行都被改、满屏 <code>^M</code></td><td><code>.gitattributes</code> 统一 <code>eol=lf</code> 或关 <code>core.autocrlf</code></td></tr><tr><td><code>Everyone</code> 可写</td><td>Codex 警告文件夹权限过宽</td><td>去掉 <code>Everyone</code> 写权限后重启 Codex</td></tr></tbody></table><blockquote><p>💡 一句话总结：路径写绝对、换行用 <code>.gitattributes</code> 锁死、权限警告别忽视——这三个坑提前堵上，Windows 体验跟 Mac 没差。</p></blockquote><hr><h2 id="_05-沙箱与权限-windows-跟-mac-linux-差在哪" tabindex="-1">05 沙箱与权限：Windows 跟 Mac/Linux 差在哪 <a class="header-anchor" href="#_05-沙箱与权限-windows-跟-mac-linux-差在哪" aria-label="Permalink to &quot;05 沙箱与权限：Windows 跟 Mac/Linux 差在哪&quot;">​</a></h2><p>Codex 的沙箱（限制它乱写文件、乱连网的安全围栏）在每个平台实现都不一样。Mac 用系统的 <code>sandbox-exec</code>，Linux 用 <code>bubblewrap</code>，<strong>Windows 是一套完全独立的、自己的两种模式。</strong></p><p>原生 Windows 上，沙箱在 <code>agent</code> 模式下会拦住「working folder 之外的文件写入」，也会拦住「没经你同意的网络访问」。你能在 <code>~/.codex/config.toml</code> 里配它（<strong>写到配置文件</strong>）：</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">windows</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sandbox = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;elevated&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 或 &quot;unelevated&quot;</span></span></code></pre></div><p>两种模式的区别，我给你拆明白：</p><table tabindex="0"><thead><tr><th>模式</th><th>强度</th><th>怎么实现</th><th>什么时候用</th></tr></thead><tbody><tr><td><code>elevated</code>（首选）</td><td>更强</td><td>专用的低权限沙箱用户 + 文件系统权限边界 + 防火墙规则 + 本地策略调整</td><td>默认就用它，性能和安全都最好</td></tr><tr><td><code>unelevated</code>（退路）</td><td>较弱</td><td>从你当前用户派生一个受限令牌 + ACL 文件系统边界 + 环境级离线控制</td><td><code>elevated</code> 装不上时顶着用</td></tr></tbody></table><p><strong>注意：这跟某些老中文教程说的「推荐 unelevated」恰恰相反。</strong> 官方明确写 <code>elevated</code> 是首选，<code>unelevated</code> 只是当 <code>elevated</code> 因为权限受限装不上时的临时退路。两种模式默认还都开了「私有桌面」做 UI 隔离，除非你为了兼容旧的 Windows Station <code>Winsta0\\Default</code> 会话桌面行为，否则别去关 <code>windows.sandbox_private_desktop</code>。</p><p><strong>为什么 <code>elevated</code> 可能装不上？</strong> 它要建专用沙箱用户、改防火墙规则、调本地策略，这些动作在公司管控电脑上经常被 IT 策略拦下来。最典型的报错是 <code>1385</code>——意思是 Windows 拒绝给沙箱用户它启动命令所需的登录权限。碰到 <code>1385</code>，按官方建议这么办：</p><ol><li>找 IT 确认设备策略有没有给「Codex 创建的沙箱用户」授予所需登录权限。</li><li>如果只有部分机器有问题，对比一下组策略或 OU 差异。</li><li>急着干活就先切 <code>unelevated</code> 顶着。</li><li>把 <code>CODEX_HOME/.sandbox/sandbox.log</code> 连同 Windows 版本一起发给团队排查。</li></ol><p><strong>同一条链路上还有个兄弟报错：<code>1223</code></strong>（这条官方文档暂未收录，来自读者在 Win11 + npm 安装环境下的实测反馈与修复验证）。症状长这样：<code>elevated</code> 模式下一让它改文件就报 <code>ShellExecuteExW failed to launch setup helper: 1223</code>，往往还伴随几条 <code>libpng warning: tRNS: invalid with alpha channel</code>，以及一个「<code>codex-windows-sandbox-setup.exe</code> → 找不到指定的模块」的弹窗。</p><p>它跟 <code>1385</code> 是同一根因家族的不同阶段：<strong><code>1385</code> 是沙箱用户在「登录阶段」被组策略拒，<code>1223</code> 是 setup helper 在「启动阶段」就没起来</strong>——出现上面那组「libpng 警告 + 找不到模块弹窗」的组合时，大概率不是 UAC 也不是杀软，而是 npm 装的 sandbox-setup 二进制或它的资源文件损坏了，重装覆盖即可（在 PowerShell 里）：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">npm.cmd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> uninstall </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">g @openai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">codex</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">npm.cmd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install   </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">g @openai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">codex</span></span></code></pre></div><p>装完切回 <code>elevated</code> 再试。所以碰到「<code>elevated</code> 模式不工作」，别东一榔头西一棒子，按这条链走：<strong>先看报错码——<code>1385</code> 找 IT 放登录权限，<code>1223</code> 用 npm 重装覆盖——都解不了，再切 <code>unelevated</code> 顶着干活。</strong></p><blockquote><p>🔒 有一个文件夹千万别外发：<code>CODEX_HOME/.sandbox-secrets/</code> 里是密钥，排障发日志时只发 <code>sandbox.log</code>，别把这个目录带上。</p></blockquote><p>如果某条命令因为「沙箱读不了某个目录」失败了，回到第 04 节那条 <code>/sandbox-add-read-dir</code> 把目录加进去就行。</p><blockquote><p>💡 一句话总结：Windows 沙箱是独立的两套，默认 <code>elevated</code>、装不上退 <code>unelevated</code>；<code>elevated</code> 报错先看码——<code>1385</code> 是公司策略卡登录权限找 IT，<code>1223</code> 多半是 npm 装的 setup helper 损坏、重装覆盖就好。</p></blockquote><hr><h2 id="_06-动手-在-windows-上跑通第一个-codex-任务" tabindex="-1">06 动手：在 Windows 上跑通第一个 Codex 任务 <a class="header-anchor" href="#_06-动手-在-windows-上跑通第一个-codex-任务" aria-label="Permalink to &quot;06 动手：在 Windows 上跑通第一个 Codex 任务&quot;">​</a></h2><p>理论讲够了，来真的。下面这套流程在原生 PowerShell 里跑，从建项目到让 Codex 改文件，全程照做。</p><p><strong>第一步，建个最小测试项目（在 PowerShell 里）：</strong></p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mkdir codex</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">win</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">test</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cd codex</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">win</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">test</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git init</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;console.log(&#39;hi&#39;)&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Out-File</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Encoding utf8 app.js</span></span></code></pre></div><blockquote><p>小提醒：老版本 PowerShell（5.1）的 <code>Out-File -Encoding utf8</code> 会给文件加个 BOM 头，可能让后面的 <code>git diff</code> 多出点编码噪音。PowerShell 7+ 可以改用 <code>Set-Content -Encoding utf8NoBOM</code> 写出不带 BOM 的文件，验证换行时更干净。</p></blockquote><p><strong>第二步，先把换行符规矩立好</strong>，免得踩开篇那个坑。在项目根目录建 <code>.gitattributes</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>* text=auto eol=lf</span></span></code></pre></div><p><strong>第三步，启动 Codex：</strong></p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">codex</span></span></code></pre></div><p>第一次跑原生沙箱，Windows 可能弹 UAC 管理员提示（这是 <code>elevated</code> 在做初始化）。自己的电脑点「同意」；如果是被锁的公司电脑点不了，Codex 通常会自动退到 <code>unelevated</code>，你会看到一行提示说切换了模式——这是正常的退路，能继续干活。</p><p><strong>第四步，给 Codex 派个最小任务</strong>，在交互界面里输入：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把 app.js 里的 &#39;hi&#39; 改成 &#39;hello, codex on windows&#39;</span></span></code></pre></div><p><strong>预期输出</strong>：Codex 会读 <code>app.js</code>、给出一段 diff、请求你批准（默认权限模式下会问你一句），你确认后它落盘。这时去看文件：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-Content</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> app.js</span></span></code></pre></div><p>应该看到：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>console.log(&#39;hello, codex on windows&#39;)</span></span></code></pre></div><p><strong>第五步，验证换行没被搞乱</strong>——这是 Windows 上最该养成的习惯：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git diff</span></span></code></pre></div><p>如果你前面 <code>.gitattributes</code> 立对了，diff 里<strong>只有那一行内容变化</strong>，不会满屏 <code>^M</code> 或者「整个文件都被改」。要是 diff 爆了，回第 04 节坑二重新处理换行。</p><p>我自己每次在新 Windows 机器上配 Codex，都会先跑一遍这个最小流程，<strong>特别是最后那步 <code>git diff</code> 验证换行</strong>——这是我用真金白银（一个下午的 issue 草稿）换来的肌肉记忆。</p><blockquote><p>💡 一句话总结：建项目 → 立 <code>.gitattributes</code> → 启动 → 派最小任务 → 用 <code>git diff</code> 验换行，五步跑通，Windows 上就算正式上路了。</p></blockquote><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>回头看这一篇，核心就这么几条：</p><ul><li><strong>默认跑法</strong>：原生 Windows + <code>elevated</code> 沙箱，官方首选，最快且安全不打折；WSL2 留给「本来就活在 Linux 里」的人。</li><li><strong>安装</strong>：一条官方 PowerShell 脚本搞定 CLI，前置盯紧 Windows 版本、<code>winget</code> 可用、管理员权限，用 IDE 扩展再备 C++ 构建工具。</li><li><strong>三个特有坑</strong>：路径写绝对、换行用 <code>.gitattributes</code> 锁成 <code>LF</code>、<code>Everyone</code> 权限警告别忽视。</li><li><strong>沙箱差异</strong>：Windows 是独立的 <code>elevated</code> / <code>unelevated</code> 两套，跟 Mac 的 <code>sandbox-exec</code>、Linux 的 <code>bubblewrap</code> 都不一样；碰到 <code>1385</code> 多半是公司策略卡登录权限，碰到 <code>1223</code> 多半是 npm 装的 setup helper 损坏、重装覆盖就好。</li></ul><p>你现在应该能：在一台干净的 Windows 机器上把 Codex 装好、判断自己该走原生还是 WSL、提前躲掉路径和换行的坑，并跑通第一个改文件的任务还顺手验了换行。</p><p>说到底，Windows 上用 Codex 不比 Mac 难，<strong>就是多了「换行」和「沙箱模式」这两层 Windows 特有的认知税</strong>，交过一次就再也不踩了。</p><hr><p>下一篇〔<a href="./34-capstone">34 综合实战</a> 〕是整个 Codex 篇的收官——咱们不再单点讲功能，而是把前面三十多篇学的东西（配置、模型、权限、子代理、自动化、迁移、Windows 适配……）拧成一股绳，从零跑一个完整的真实项目。</p><p>留个小思考：如果让你现在挑一个项目，从 <code>git clone</code> 到让 Codex 帮你跑通第一个功能，你会先配哪三样、先立哪条规矩？下一篇见分晓。</p>`,118)])])}const k=s(d,[["render",a]]);export{g as __pageData,k as default};
